class Solution:
    def checkPartitioning(self, s):
        n = len(s)
        def isPal(a, b):
            while a < b:
                if s[a] != s[b]:
                    return False
                a += 1
                b -= 1
            return True
        for i in range(1, n - 1):
            if not isPal(0, i - 1):
                continue
            for j in range(i + 1, n):
                if isPal(i, j - 1) and isPal(j, n - 1):
                    return True
        return False

